diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 456f5086309c..b521a9ca2a63 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -639,6 +639,22 @@ static Decomposition decompose(Value *V,
     return ResA;
   }

+  // Handle saturating subtraction intrinsics.
+  // usub.sat(A, B) <= A (unsigned), ssub.sat(A, B) <= A (signed).
+  // When decomposing for the corresponding signedness, we can use A directly
+  // since the saturating result is bounded by A.
+  if (auto *SI = dyn_cast<SaturatingInst>(V)) {
+    Value *A = SI->getLHS();
+    if (SI->getIntrinsicID() == Intrinsic::usub_sat && !IsSigned) {
+      // usub.sat(A, B) <= A (unsigned), safe to decompose as A for unsigned.
+      return decompose(A, Preconditions, IsSigned, DL);
+    }
+    if (SI->getIntrinsicID() == Intrinsic::ssub_sat && IsSigned) {
+      // ssub.sat(A, B) <= A (signed), safe to decompose as A for signed.
+      return decompose(A, Preconditions, IsSigned, DL);
+    }
+  }
+
   return {V, IsKnownNonNegative};
 }

@@ -1115,7 +1131,7 @@ void State::addInfoFor(BasicBlock &BB) {
         WorkList.emplace_back(FactOrCheck::getConditionFact(
             DT.getNode(I.getParent()), Pred, A, B));
       } else {
-        WorkList.emplace_back(
+        WorkList.push_back(
             FactOrCheck::getInstFact(DT.getNode(I.getParent()), &I));
       }
       break;
@@ -1141,10 +1157,13 @@ void State::addInfoFor(BasicBlock &BB) {
         break;
       [[fallthrough]];
     case Intrinsic::abs:
+    case Intrinsic::usub_sat:
+    case Intrinsic::ssub_sat:
+    case Intrinsic::uadd_sat:
+    case Intrinsic::sadd_sat:
       WorkList.push_back(FactOrCheck::getInstFact(DT.getNode(&BB), &I));
       break;
     }
-
     GuaranteedToExecute &= isGuaranteedToTransferExecutionToSuccessor(&I);
   }

@@ -1436,6 +1455,11 @@ static bool checkAndReplaceCondition(
     Constant *ConstantC = ConstantInt::getBool(
         CmpInst::makeCmpResultType(Cmp->getType()), IsTrue);
     bool Changed = false;
+
+    // Remember operands to check if they become unused after replacement.
+    Value *Op0 = Cmp->getOperand(0);
+    Value *Op1 = Cmp->getOperand(1);
+
     Cmp->replaceUsesWithIf(ConstantC, [&DT, NumIn, NumOut, ContextInst,
                                        &Changed](Use &U) {
       auto *UserI = getContextInstForUse(U);
@@ -1456,6 +1480,16 @@ static bool checkAndReplaceCondition(
     NumCondsRemoved++;
     if (Cmp->use_empty())
       ToRemove.push_back(Cmp);
+
+    // If any operand is a saturating intrinsic that is now unused, add it to
+    // the removal list.
+    if (auto *SI = dyn_cast<SaturatingInst>(Op0))
+      if (SI->use_empty())
+        ToRemove.push_back(SI);
+    if (auto *SI = dyn_cast<SaturatingInst>(Op1))
+      if (SI->use_empty())
+        ToRemove.push_back(SI);
+
     return Changed;
   };

@@ -1891,13 +1925,39 @@ static bool eliminateConstraints(Function &F, DominatorTree &DT, LoopInfo &LI,
         AddFact(CmpInst::ICMP_SGE, CB.Inst, X);
         continue;
       }
-
       if (auto *MinMax = dyn_cast<MinMaxIntrinsic>(CB.Inst)) {
         Pred = ICmpInst::getNonStrictPredicate(MinMax->getPredicate());
         AddFact(Pred, MinMax, MinMax->getLHS());
         AddFact(Pred, MinMax, MinMax->getRHS());
         continue;
       }
+
+      // Handle saturating add/subtract intrinsics.
+      if (auto *SatInst = dyn_cast<SaturatingInst>(CB.Inst)) {
+        Value *A = SatInst->getLHS();
+        Value *B = SatInst->getRHS();
+        switch (SatInst->getIntrinsicID()) {
+        case Intrinsic::usub_sat:
+          // usub.sat(A, B) <= A (unsigned)
+          AddFact(CmpInst::ICMP_ULE, CB.Inst, A);
+          break;
+        case Intrinsic::ssub_sat:
+          // ssub.sat(A, B) <= A (signed)
+          AddFact(CmpInst::ICMP_SLE, CB.Inst, A);
+          break;
+        case Intrinsic::uadd_sat:
+          // uadd.sat(A, B) >= A (unsigned)
+          AddFact(CmpInst::ICMP_UGE, CB.Inst, A);
+          break;
+        case Intrinsic::sadd_sat:
+          // sadd.sat(A, B) >= A (signed)
+          AddFact(CmpInst::ICMP_SGE, CB.Inst, A);
+          break;
+        default:
+          llvm_unreachable("unexpected saturating intrinsic");
+        }
+        continue;
+      }
     }

     Value *A = nullptr, *B = nullptr;

