{"command": "cd /root/auto-opt/utils/llvm-135557 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/Scalar/ConstraintElimination.cpp 1453 1479
  auto ReplaceCmpWithConstant = [&](CmpInst *Cmp, bool IsTrue) {
    generateReproducer(Cmp, ReproducerModule, ReproducerCondStack, Info, DT);
    Constant *ConstantC = ConstantInt::getBool(
        CmpInst::makeCmpResultType(Cmp->getType()), IsTrue);
    bool Changed = false;

    // Remember operands to check if they become unused after replacement.
    Value *Op0 = Cmp->getOperand(0);
    Value *Op1 = Cmp->getOperand(1);

    Cmp->replaceUsesWithIf(ConstantC, [&DT, NumIn, NumOut, ContextInst,
                                       &Changed](Use &U) {
      auto *UserI = getContextInstForUse(U);
      auto *DTN = DT.getNode(UserI->getParent());
      if (!DTN || DTN->getDFSNumIn() < NumIn || DTN->getDFSNumOut() > NumOut)
        return false;
      if (UserI->getParent() == ContextInst->getParent() &&
          UserI->comesBefore(ContextInst))
        return false;

      // Conditions in an assume trivially simplify to true. Skip uses
      // in assume calls to not destroy the available information.
      auto *II = dyn_cast<IntrinsicInst>(U.getUser());
      bool ShouldReplace = !II || II->getIntrinsicID() != Intrinsic::assume;
      Changed |= ShouldReplace;
      return ShouldReplace;
    });
    NumCondsRemoved++;
    if (Cmp->use_empty())
      ToRemove.push_back(Cmp);

    // If any operand is a saturating intrinsic that is now unused, add it to
    // the removal list.
    if (auto *SI = dyn_cast<SaturatingInst>(Op0))
      if (SI->use_empty())
        ToRemove.push_back(SI);
    if (auto *SI = dyn_cast<SaturatingInst>(Op1))
      if (SI->use_empty())
        ToRemove.push_back(SI);

    return Changed;
  };
CODEEOF"}

